ZYNQ.peer.sendTo('id', 'hello')

ZYNQ.peer.broadcast('hello')

ZYNQ.peer.on('message', ({ peerId, message }) => {
  console.log(message)
})

ZYNQ.peer.connect('id', {
  video: true,
  audio: true,
  resolution: 720,
  fps: 30
})

ZYNQ.peer.on('local-stream', stream => {
  video.srcObject = stream
})

ZYNQ.peer.on('remote-stream', ({ stream }) => {
  video.srcObject = stream
})
